('chunk_eabbe877c1f237d3ec','file_635d854e419faefdf1','pahe.md','Subject Overview','Physical and Health Education (PHE) is one of the eight MYP subject groups. It develops **knowledge, skills and attitudes** that help students achieve and maintain a healthy, active lifestyle. Students learn *through* physical activity, not just *about* it — combining physical performance with critical thinking, reflection and healthy decision-making.','{"subject":2,"overview":1,"physical":3,"and":4,"health":1,"education":1,"phe":1,"one":1,"the":1,"eight":1,"myp":1,"groups":1,"develops":1,"knowledge":1,"skills":1,"attitudes":1,"that":1,"help":1,"students":2,"achieve":1,"maintain":1,"healthy":2,"active":1,"lifestyle":1,"learn":1,"through":1,"activity":1,"not":1,"just":1,"about":1,"combining":1,"performance":1,"with":1,"critical":1,"thinking":1,"reflection":1,"decision":1,"making":1}'::jsonb),
